import sys
it = iter(sys.stdin.read().split())
n = int(next(it))
m = int(next(it))
cards = [[int(next(it)) for _ in range(m)] for _ in range(n)]

def possible(max_points):
    count = [0] * n
    for i in range(n):
        for point in sorted(cards[i], reverse=True):
            if count[i] + point <= max_points:
                count[i] += point
            else:
                break
    return sum(count) >= sum(sum(row) for row in cards)

low = 0
high = sum(sum(row) for row in cards)
while low < high:
    mid = (low + high) // 2
    if possible(mid):
        high = mid
    else:
        low = mid + 1
print(low)

