#include <bits/stdc++.h>
using namespace std;
int main(){
    int n, m;
    cin >> n >> m;
    vector<vector<int>> cards(n, vector<int>(m));
    for(int i = 0; i < n; i++)
        for(int j = 0; j < m; j++)
            cin >> cards[i][j];

    auto possible = [&](long long max_points){
        vector<long long> count(n);
        for(int i = 0; i < n; i++) {
            sort(cards[i].rbegin(), cards[i].rend());
            for(int point : cards[i]) {
                if(count[i] + point <= max_points) {
                    count[i] += point;
                } else {
                    break;
                }
            }
        }
        long long total = 0;
        for(int i = 0; i < n; i++)
            total += count[i];
        long long cards_total = 0;
        for(int i = 0; i < n; i++)
            for(int j = 0; j < m; j++)
                cards_total += cards[i][j];
        return total >= cards_total;
    };

    long long low = 0;
    long long high = 0;
    for(int i = 0; i < n; i++)
        for(int j = 0; j < m; j++)
            high += cards[i][j];
    while(low < high) {
        long long mid = low + (high - low) / 2;
        if(possible(mid)) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    cout << low << endl;
    return 0;
}
